// Parse incoming webhook data
const input = $input.first().json;
const body = input.body ?? input;

const projectName = body.project_name?.trim();
if (!projectName) throw new Error('project_name is required');

const trelloBoardLink = body.trello_board_link?.trim() || null;
const membersRaw = body.members || [];
if (!Array.isArray(membersRaw) || membersRaw.length === 0) throw new Error('members must be a non-empty array');

// Find leader (first with role='leader' or fallback to first member)
const leader = membersRaw.find(m => m.role === 'leader') || membersRaw[0];
if (!leader.email) throw new Error('Leader must have an email');

// Extract board ID from link if provided
let boardId = null;
if (trelloBoardLink) {
  const match = trelloBoardLink.match(/\/(?:b|invite\/b)\/([A-Za-z0-9]+)/);
  if (!match) throw new Error('Invalid Trello board link');
  boardId = match[1];
}

return {
  json: {
    project_name: projectName,
    trello_board_link: trelloBoardLink,
    boardId: boardId,
    hasBoardLink: !!trelloBoardLink,
    members: membersRaw.map(m => ({ email: m.email, name: m.name || m.email, role: m.role || 'member' })),
    leader: leader
  }
};

// ============================================================
// 1. SAFELY GET EXTERNAL DATA (Board Members & Lists)
// ============================================================
let membersOnBoard = [];
try {
  const membersItems = $('Get Board Members').all() || [];
  membersOnBoard = membersItems.flatMap(item => item.json).filter(m => m && m.email);
} catch (e) {
  console.log('Could not read board members:', e.message);
}

let existingLists = [];
try {
  const listsItems = $('Get Board Lists').all() || [];
  existingLists = listsItems.flatMap(item => item.json).filter(l => l && l.id);
} catch (e) {
  console.log('Could not read board lists:', e.message);
}

// ============================================================
// 2. GET ORIGINAL PROJECT DATA (from Parse Input)
// ============================================================
const parseItems = $('Parse Input').all();
if (!parseItems || parseItems.length === 0) {
  throw new Error('Parse Input node returned no data. Check webhook payload.');
}
const originalItem = parseItems[0].json;
if (!originalItem) {
  throw new Error('Parse Input node returned empty JSON.');
}

const projectName = originalItem.project_name;
if (!projectName) throw new Error('project_name is missing.');

const boardId = originalItem.boardId;
if (!boardId) throw new Error('boardId is missing. Valid Trello board link required.');

const members = originalItem.members;
if (!Array.isArray(members) || members.length === 0) {
  throw new Error('members array is missing or empty.');
}

const leader = members.find(m => m.role === 'leader') || members[0];
if (!leader || !leader.email) {
  throw new Error('Leader not found. Provide one member with role="leader".');
}

// ============================================================
// 3. MEMBERS TO ADD (skip existing emails)
// ============================================================
const existingEmails = new Set(
  membersOnBoard
    .map(m => m.email?.trim().toLowerCase())
    .filter(email => email && email !== 'undefined')
);

const membersToAdd = members.filter(m => {
  const email = m.email.trim().toLowerCase();
  return !existingEmails.has(email);
});

const addMemberRequests = membersToAdd.map(member => ({
  email: member.email,
  fullName: member.name || member.email,
  isLeader: member.email === leader.email,
  boardId: boardId
}));

// ============================================================
// 4. LISTS TO CREATE (skip existing, case‑insensitive, synonyms)
// ============================================================
const canonicalLists = ['Backlog', 'Ongoing', 'To Test', 'To Integrate', 'Done'];

const synonymMap = {
  'backlog': ['backlog', 'todo', 'to be done', 'product backlog', 'icebox'],
  'ongoing': ['ongoing', 'in progress', 'doing', 'wip', 'development'],
  'to test': ['to test', 'testing', 'qa', 'review'],
  'to integrate': ['to integrate', 'integration', 'deploy', 'release'],
  'done': ['done', 'complete', 'completed', 'finished', 'closed']
};

// Normalize existing list names (lowercase, trimmed)
const existingListNames = existingLists
  .map(l => l.name?.trim().toLowerCase() || '')
  .filter(name => name !== '');

const listsToCreate = [];
for (const canonical of canonicalLists) {
  const canonicalLower = canonical.toLowerCase();
  const synonyms = synonymMap[canonicalLower] || [canonicalLower];

  // Check if any synonym exists in the board's list names
  const exists = existingListNames.some(listName =>
    synonyms.some(syn => listName.includes(syn))
  );

  if (!exists) {
    listsToCreate.push({ name: canonical, boardId: boardId });
  }
}

// ============================================================
// 5. LOGGING (for debug – shows what will be created)
// ============================================================
console.log(`Members to add: ${addMemberRequests.length}`);
console.log(`Lists to create: ${listsToCreate.length}`);

return {
  json: {
    boardId: boardId,
    addMemberRequests: addMemberRequests,
    listsToCreate: listsToCreate,
    membersAddedCount: addMemberRequests.length,
    listsCreatedCount: listsToCreate.length,
    project_name: projectName,
    leader: leader,
    members: members
  }
};

// Directly get the original data from the Reconcile node
const reconcile = $('Reconcile Members & Lists').first().json;

return {
  json: {
    project_name: reconcile.project_name,
    trello_board_id: reconcile.boardId,
    team_emails: reconcile.members.map(m => m.email),
    leader_email: reconcile.leader.email,
    members: reconcile.members,
    leader: reconcile.leader,
    board_url: `https://trello.com/b/${reconcile.boardId}`
  }
};

// Try to get data from various sources in order of preference
let data = null;

// 1. First, try the incoming data (if it already contains members)
if ($input && $input.first() && $input.first().json && $input.first().json.members) {
  data = $input.first().json;
}
// 2. If not, try absolute reference to 'Prepare DB Data' (true branch)
else if ($('Prepare DB Data') && $('Prepare DB Data').first() && $('Prepare DB Data').first().json) {
  data = $('Prepare DB Data').first().json;
}
// 3. If still not, try 'Finalize New Board' (false branch)
else if ($('Finalize New Board') && $('Finalize New Board').first() && $('Finalize New Board').first().json) {
  data = $('Finalize New Board').first().json;
}
// 4. Last resort: try 'Reconcile Members & Lists'
else if ($('Reconcile Members & Lists') && $('Reconcile Members & Lists').first() && $('Reconcile Members & Lists').first().json) {
  data = $('Reconcile Members & Lists').first().json;
}
else {
  throw new Error('Could not find members data from any source node. Check workflow connections.');
}

// Validate members array
if (!data.members || !Array.isArray(data.members) || data.members.length === 0) {
  throw new Error('Members array is missing or empty in the data source.');
}

// Determine leader email
let leaderEmail = data.leader_email || (data.leader && data.leader.email);
if (!leaderEmail) {
  // Fallback: find member with role 'leader'
  const leaderMember = data.members.find(m => m.role === 'leader');
  if (leaderMember) leaderEmail = leaderMember.email;
  else leaderEmail = data.members[0]?.email; // fallback to first member
}
if (!leaderEmail) throw new Error('Could not determine leader email.');

// Get board URL or ID
const boardId = data.trello_board_id || data.boardId;
const boardUrl = data.board_url || `https://trello.com/b/${boardId}`;
const projectName = data.project_name;

// Filter out leader
const regularMembers = data.members.filter(m => m.email !== leaderEmail);

// If no regular members, return empty array (email node will be skipped)
if (regularMembers.length === 0) {
  return [];
}

// Prepare one item per regular member for the email node
return regularMembers.map(member => ({
  json: {
    email: member.email,
    name: member.name || member.email,
    board_url: boardUrl,
    project_name: projectName
  }
}));

// Use the incoming data directly (from the IF node's false branch)
const input = $input.first().json;

const projectName = input.project_name;
const members = input.members;
const leader = input.leader;

// Prepare data for board creation
return {
  json: {
    project_name: projectName,
    members: members,
    leader: leader,
    // Use standard list names (synonyms handled later if needed)
    lists: ['Backlog', 'Ongoing', 'To Test', 'To Integrate', 'Done']
  }
};

// Get the board data directly from the Create Trello Board node
const board = $('Create Trello Board').first().json;
if (!board || !board.id) {
  throw new Error('Could not read board ID from Create Trello Board node.');
}
const boardId = board.id;

// Get the member list and leader from Prepare Create Board node
const setup = $('Prepare Create Board').first().json;
if (!setup || !setup.members) {
  throw new Error('Could not read member data from Prepare Create Board node.');
}
const members = setup.members;
const leader = setup.leader;

// Create one request per member (leader gets 'admin' type)
return members.map(m => ({
  json: {
    boardId: boardId,
    email: m.email,
    type: m.email === leader.email ? 'admin' : 'normal'
  }
}));

// Use the output of the previous node (Create Trello Board) and the original setup data
const board = $input.first().json; // from Create Trello Board
const setup = $('Prepare Create Board').first().json; // still need original members

const boardId = board.id;
const projectName = setup.project_name;
const members = setup.members;
const leader = setup.leader;
const memberEmails = members.map(m => m.email);

return {
  json: {
    project_name: projectName,
    trello_board_id: boardId,
    team_emails: memberEmails,
    leader_email: leader.email,
    board_url: `https://trello.com/b/${boardId}`,
    members: members,
    leader: leader
  }
};

// Get data directly from Finalize New Board node
const final = $('Finalize New Board').first().json;

// Validate required fields
if (!final || !final.members) {
  throw new Error('Finalize New Board did not return valid members data');
}
if (!final.leader || !final.leader.email) {
  throw new Error('Leader email missing in Finalize New Board data');
}

const leaderEmail = final.leader.email;
const regularMembers = final.members.filter(m => m.email !== leaderEmail);

// If no regular members, return empty array (email node will be skipped)
if (regularMembers.length === 0) {
  return [];
}

// Map each regular member to the format expected by the email node
return regularMembers.map(m => ({
  json: {
    email: m.email,
    name: m.name || m.email,
    board_url: final.board_url,
    project_name: final.project_name
  }
}));

// Get board ID from Create Trello Board node
const board = $('Create Trello Board').first().json;
// Get lists and other data from Prepare Create Board node
const setup = $('Prepare Create Board').first().json;

return {
  json: {
    boardId: board.id,           // <-- plain field
    lists: setup.lists,          // array of list names
    project_name: setup.project_name,
    members: setup.members,
    leader: setup.leader
  }
};
